    private synchronized void build() {
        // double check flag
        if (builtAccel != 0)
            return;
        if (primitives != null) {
            int n = primitives.getNumPrimitives();
            if (n >= 1000)
                UI.printInfo(Module.GEOM, "Building acceleration structure for %d primitives ...", n);
            accel = AccelerationStructureFactory.create(acceltype, n, true);
